ctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; folders&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 폴더 이름에서 숫자를 추출하는 함수&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;extract_number&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;folder_name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;# 정규 표현식을 사용하여 폴더 이름에서 숫자를 추출&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;match&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; re&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;search&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;r&#39;\d+&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; folder_name&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;match&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;match&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;group&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;float&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;inf&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 숫자가 없는 경우 무한대 값을 반환&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# README.md 파일을 업데이트하는 함수&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;update_readme&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;repo&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; folders&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; original_content&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;# 기존 &#34;## 📑Quest List📑&#34; 섹션과 그 이하 내용을 제거&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    start_index &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; original_content&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;find&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;## 📑Quest List📑&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; start_index &lt;span class=&#34;token operator&#34;&gt;!=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        original_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; original_content&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;start_index&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;# 새로운 &#34;## 📑Quest List📑&#34; 섹션 및 테이블을 생성&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    new_table &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;## 📑Quest List📑\n\n&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    new_table &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;| 퀘스트명 | URL |\n&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    new_table &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;| --- | --- |\n&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;# 폴더를 숫자로 정렬하여 목록을 만듭니다.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    sorted_folders &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;sorted&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;folders&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; key&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;lambda&lt;/span&gt; x&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; extract_number&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;name&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; folder &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; sorted_folders&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        folder_name &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; folder&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;name&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        folder_url &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; folder&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;html_url&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        new_table &lt;span class=&#34;token operator&#34;&gt;+=&lt;/span&gt; &lt;span class=&#34;token string-interpolation&#34;&gt;&lt;span class=&#34;token string&#34;&gt;f&#34;| &lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;folder_name&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt; | [Link](&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;folder_url&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;) |\n&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;# README.md 파일의 기존 내용 끝에 새로운 테이블을 추가&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    updated_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; original_content &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; new_table&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; updated_content&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 사용자가 자신의 GitHub 리포지토리 이름을 여기에 입력&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;user_repo &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# Enter your GitHub repository (format: username/repository)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 기존 README.md 내용을 읽어옵니다.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;try&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;README.md&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;r&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        original_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;read&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;except&lt;/span&gt; FileNotFoundError&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    original_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 저장소에서 폴더 목록을 가져오고 README.md 파일을 업데이트&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;folders &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; get_folders&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;user_repo&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;updated_content &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; update_readme&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;user_repo&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; folders&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; original_content&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 업데이트된 내용을 README.md 파일에 업데이트&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;open&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;README.md&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;w&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;as&lt;/span&gt; &lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token builtin&#34;&gt;file&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;write&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;updated_content&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;제가 사용하는 것과 동일하게 사용하고자 한다면 예제코드에서 본인의 github user명과 적용할 respsitory만 변경하여 사용하면 됩니다.
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;update_readme.py&lt;/code&gt;  로 repository의 가장 main 페이지에 저장하면 됩니다.&lt;/li&gt;
&lt;li&gt;이후 이  &lt;code&gt;update_readme.py&lt;/code&gt; 를 GitHub Action에서 불러와서 사용하도록 할 예정입니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;표의 내용을 바꾸고 싶다면  &lt;code&gt;update_readme&lt;/code&gt;  함수의 내용을 수정하시면 됩니다.&lt;/li&gt;
&lt;li&gt;예제 코드 다운 받기 👉 &lt;a href=&#34;../../../../assets/attached_files/update_readme.py&#34;&gt;파일 다운로드 링크&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;2-github-action-설정&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-github-action-설정&#34;&gt;#&lt;/a&gt; 2. GitHub Action 설정&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;이제 위에서 설정한 Python 스크립트가 GitHub의 Repository에 새로운 commit이 있을 때 마다 자동으로 실행되도록 GitHub Action을 설정합니다.&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;1️⃣ GitHub Action 설정 항목 몇 가지를 조정&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;settings&lt;/code&gt;  👉  &lt;code&gt;Actions&lt;/code&gt;  👉  &lt;code&gt;General&lt;/code&gt;  을 선택해 GitHub Action의 옵션으로 이동합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/3VLcF30.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;2가지 옵션을 확인합니다.
&lt;ul&gt;
&lt;li&gt;Actions permisssions
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Allow all actions and reusable workflows&lt;/code&gt;  에 체크가 되어야 합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Workflow permissions&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Read and write permissions&lt;/code&gt;  에 체크가 되어 있어야 합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/lEAJB2k.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;2️⃣  &lt;code&gt;.github/workflows&lt;/code&gt;  폴더 생성&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;작업을 적용할 Repository의 root dir에  &lt;code&gt;.github/workflows&lt;/code&gt;  라는 폴더를 생성합니다.&lt;/li&gt;
&lt;li&gt;이 폴더는 GitHub Action의 워크플로우 설정 파일들을 저장하는 곳입니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;3️⃣ 워크플로우 설정 파일 생성 및 설정 작성&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;update-readme.yml&lt;/code&gt;  파일을 생성한 뒤 워크플로우 설정을 작성합니다.&lt;/li&gt;
&lt;li&gt;워크플로우 작성시에는 2가지를 설정해주면 됩니다.
&lt;ul&gt;
&lt;li&gt;트리거 : 워크플로우가 언제 실행될지 설정&lt;/li&gt;
&lt;li&gt;작업설정 : 워크플로우에서 실행할 작업 설정정&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;제가 사용하고 있는 워크플로우 설정은 아래와 같습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight yml&#34;&gt;&lt;figcaption data-lang=&#34;YAML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Update README&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key atrule&#34;&gt;on&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token key atrule&#34;&gt;push&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token key atrule&#34;&gt;branches&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; main&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key atrule&#34;&gt;jobs&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token key atrule&#34;&gt;update-readme&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token key atrule&#34;&gt;runs-on&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; ubuntu&lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt;latest&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token key atrule&#34;&gt;steps&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Checkout&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;uses&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; actions/checkout@v2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Set up Python&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;uses&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; actions/setup&lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt;python@v2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;with&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          &lt;span class=&#34;token key atrule&#34;&gt;python-version&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;3.8&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Install dependencies&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;run&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; pip install requests&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Update README&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;run&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; python update_readme.py&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;token key atrule&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; Commit and Push&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token key atrule&#34;&gt;run&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;|&lt;/span&gt;&lt;span class=&#34;token scalar string&#34;&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          git config --global user.name &#39;Your Name&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          git config --global user.email &#39;your-email@example.com&#39;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          git add README.md&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          git commit -m &#34;Update README&#34;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;          git push&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;각 내용에 대한 설명은 아래와 같습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;워크플로우 이름 설정 ( &lt;code&gt;name&lt;/code&gt; )&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Update README&lt;/code&gt; : 이 워크플로우의 이름입니다. GitHub Actions 탭에서 이 이름으로 워크플로우를 찾을 수 있습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;트리거 설정 ( &lt;code&gt;on&lt;/code&gt; )&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;push&lt;/code&gt; : 이 워크플로우는  &lt;code&gt;push&lt;/code&gt;  이벤트에 의해 트리거됩니다.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;- main&lt;/code&gt; :  &lt;code&gt;main&lt;/code&gt;  브랜치에 대한  &lt;code&gt;push&lt;/code&gt;  이벤트가 발생할 때마다 이 워크플로우가 실행됩니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;작업 설정 ( &lt;code&gt;jobs&lt;/code&gt; )&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;update-readme&lt;/code&gt; : 이 작업의 ID입니다. 여기서는 &#39;README 파일을 업데이트하는 작업&#39;이라는 의미입니다.&lt;/li&gt;
&lt;li&gt;&lt;code&gt;runs-on: ubuntu-latest&lt;/code&gt; : 이 작업은 최신 버전의 Ubuntu 가상 환경에서 실행됩니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;작업 단계 ( &lt;code&gt;steps&lt;/code&gt; )&lt;/strong&gt;:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Checkout&lt;/strong&gt;: 현재 리포지토리를 체크아웃합니다. 이를 통해 리포지토리의 파일에 접근할 수 있습니다.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Set up Python&lt;/strong&gt;: Python 환경을 설정합니다.  &lt;code&gt;python-version: &#39;3.8&#39;&lt;/code&gt; 을 통해 Python 3.8 버전을 사용하도록 설정합니다.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Install dependencies&lt;/strong&gt;: 필요한 Python 패키지를 설치합니다. 여기서는  &lt;code&gt;requests&lt;/code&gt;  모듈을 설치합니다.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Update README&lt;/strong&gt;:  &lt;code&gt;update_readme.py&lt;/code&gt; 라는 Python 스크립트를 실행합니다. 이 스크립트는  &lt;code&gt;README.md&lt;/code&gt;  파일을 업데이트하는 로직을 포함하고 있습니다.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Commit and Push&lt;/strong&gt;: 변경된  &lt;code&gt;README.md&lt;/code&gt;  파일을 깃허브 리포지토리에 커밋하고 푸시합니다. 사용자 이름과 이메일 주소를 설정한 후,  &lt;code&gt;git add&lt;/code&gt; ,  &lt;code&gt;git commit&lt;/code&gt; ,  &lt;code&gt;git push&lt;/code&gt;  명령을 사용합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;hr /&gt;
&lt;ul&gt;
&lt;li&gt;예제 코드 다운 받기 👉 &lt;a href=&#34;../../../../assets/attached_files/update_readme.yml&#34;&gt;파일 다운로드 링크&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3-스크립트-실행-및-확인&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-스크립트-실행-및-확인&#34;&gt;#&lt;/a&gt; 3. 스크립트 실행 및 확인&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;이제 생성한 워크플로우 파일을 저장한 뒤 실제 스크립트가 잘 작동하는지 확인합니다.&lt;/li&gt;
&lt;li&gt;새로운 폴더를 추가하거나 기존 폴더 이름을 변경해  &lt;code&gt;README.md&lt;/code&gt; 의 파일이 올바르게 업데이트 되는지 확인합니다.&lt;/li&gt;
&lt;li&gt;올바르게 작성이 되었다면 아래의 이미지처럼 기존 README.md의 내용을 유지하면서 repository에 포함된 폴더명을 기반으로 표를 만들고 링크가 작성되어 있을 것입니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/FQ7gUxT.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;위 작업이 적용된 저의 Repository입니다. 👉 &lt;a href=&#34;https://github.com/Kimgabe/AIFFEL_Online_Quest&#34;&gt;Repository 구경하기&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h2 id=&#34;outro&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#outro&#34;&gt;#&lt;/a&gt; 😀 Outro.&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;이번 포스팅에서는 GitHub Action과 파이썬을 활용해 내 GitHub의 Repository의 목록을 자동으로 업데이트하는 방법에 대해 살펴봤습니다.&lt;/li&gt;
&lt;li&gt;이 방법을 적용해 프로젝트 관리를 수월하게 할 수 있고, 외부인에게 해당 Repository의 내용을 좀 더 높은 가독성과 접근성을 제공할 수 있습니다.&lt;/li&gt;
&lt;li&gt;또한 이 과정을 통해 기본적인 GitHub Action의 작동 방식을 이해함으로서 다른 자동화 방법을 발굴 및 적용할 수 있을 것입니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;references&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#references&#34;&gt;#&lt;/a&gt; References&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://docs.github.com/ko/enterprise-cloud@latest/actions&#34;&gt;Github Actions&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://docs.github.com/ko/enterprise-cloud@latest/actions/automating-builds-and-tests/building-and-testing-python&#34;&gt;Python 빌드 및 테스트&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;hr /&gt;
&lt;h2 id=&#34;summary&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#summary&#34;&gt;#&lt;/a&gt; 🚦Summary&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;이 과정을 거치면 기존에 보유한 여러 Repository를 하나의 Repository 아래에 두어 정리하고 관리할 수 있습니다.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;정확히는 기존 Repository 를 하나의 Repository 로 옮기고, 기존 Repository 를 삭제하는 방식입니다.&lt;/li&gt;
&lt;li&gt;그럼에도 불구하고! 과거에 commit한 나의 잔디는 지킬 수 있다는 장점이 있습니다. 😀&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이 작업은 Git 의 Subtree 라는 개념을 사용한 방법 입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;intro&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#intro&#34;&gt;#&lt;/a&gt; 📌Intro&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;최근 AIFFEL이라는 부트캠프를 시작하면서 여러 퀘스트를 위해 동기들의 레포지토리를 fork 해와서 pull request 하는 작업을 반복하고 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&#34;GitHub.md&#34;&gt;GitHub&lt;/a&gt; 의 사용법도 익히고, co-work를 하는 방법을 배운다는 점에서 좋기는 하지만 (개인적인) 단점이 있습니다. 매번 여러 동기들의 레포지토리를 fork 해오다보니 개인 레포지토리에 비슷한 이름의 레포지토리가 여러개 생겨나기도하고, 그전부터 무분별하게 fork 해오던 레포지토리들이 그득 해서 이참에 정리를 해야겠다 마음 먹었습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;하나의 레포지 토리 안에 다른 레포지토리들을 넣어서 관리할 수 없을까? (내가 쌓아온 잔디를 잃지 않으면서!) 라는 생각이 들었고, 구글링과 gpt의 힘을 빌어 방법을 찾았고, 기록삼아 포스팅을 해봅니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;기존의-나의-repository-들&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#기존의-나의-repository-들&#34;&gt;#&lt;/a&gt; 기존의 나의 Repository 들..&lt;/h3&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/3zrXqfc.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;동일한 이름에 동기들의 username으로 구분을 했지만, 왠지 보기에 Repository 가 조잡해보입니다.&lt;/li&gt;
&lt;li&gt;이러면 정리하고 싶은 욕구가 마구 샘솟습니다. 자주 쓰지도 않을 건데 메인 폴더에 안쓰는 폴더들이 넘쳐나는 기분입니다.&lt;/li&gt;
&lt;li&gt;하지만 언제 또 이 동료들과 협업을 할지 모르니 fork한 것들을 지우고 싶지는 않습니다.&lt;/li&gt;
&lt;li&gt;자료관리의 기본은 역시 동일 카테고리로 묶는 것인데 깃허브에서는 각각의 Repository 가 하나의 프로그램을 이루는 경우가 많다보니 이것이 쉽지 않습니다.&lt;/li&gt;
&lt;li&gt;하지만 Git의 Subtree 개념을 사용한다면 이 작업이 어느정도 구현 가능합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✔️ 제 목표는&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;제가 AIFFEL을 들으면서 Quest를 하는  &lt;code&gt;AIFFEL_Online_Quest&lt;/code&gt;  repository 안에 fork 해온 동료들의 Repository 를 옮기는 것입니다.&lt;/li&gt;
&lt;li&gt;하지만, 이전에 동료들과 했던 소중한 제 잔디를 지우고싶지는 않습니다.&lt;/li&gt;
&lt;li&gt;이걸 가능하게 해주는게 Git의 subtree라는 개념입니다. subtree의 개념에 대해서는 포스팅 맨 마지막에 정리하도록 하겠습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;필요-사항&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#필요-사항&#34;&gt;#&lt;/a&gt; 필요 사항&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;로컬 pc(개인 컴퓨터)에 git이 설치가 되어 있어야 합니다.&lt;/li&gt;
&lt;li&gt;그리고 git의 명령어를 어느정도 사용할 줄 알아야 합니다. (하지만 필요한 명령어는 모두 여기에서 알려드립니다!)&lt;/li&gt;
&lt;li&gt;왕초보인 저도 하나씩 따라하다보니 가능했습니다. 모두가 가능할거라 생각합니다 😀&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;전체-과정-미리보기&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#전체-과정-미리보기&#34;&gt;#&lt;/a&gt; 🔭전체 과정 미리보기&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;잡다한 repository를 관리할 repository를 새로 만든다.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;정리할 폴더가 이미 있다면 이 단계를 스킵하고 2번 부터 진행하시면 됩니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;해당 repository를 내 로컬 pc에 clone한다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;clone한 repository에 git commit을 한다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이후 subtree 명령어를 사용해 관리하고 싶은 repository들을 하나의 repository로 이동시킨다.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;엄밀히는 해당 &#39;repository의 subtree를 관리할 repository에 생성시킨다.&#39;  가 더 맞는 표현이긴 합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;기존의 repository를 삭제한다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;변경된 Repository 의 구조는 아래 이미지와 같습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/qD66ri7.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;repository-합치기-1-여러-repository를-저장할-repository를-생성&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#repository-합치기-1-여러-repository를-저장할-repository를-생성&#34;&gt;#&lt;/a&gt; Repository 합치기 (1) - 여러 Repository를 저장할 Repository를 생성&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;💡 물론 기존의 Repository에 여러 Repository를 저장하는 것도 가능합니다.&lt;/p&gt;
&lt;p&gt;기존에 보유한 Repository에 바로 여러 Repository를 옮기는 것은 Repository 합치기(2) 부터 작업하시면 됩니다.&lt;/p&gt;
&lt;p&gt;💁 Git 설치가 필요하다면 아래의 링크를 통해 다운받을 수 있습니다. 👉 &lt;a href=&#34;https://git-scm.com/download/win&#34;&gt;Git 다운로드&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;hr /&gt;
&lt;h4 id=&#34;1-새로운-repository-생성&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-새로운-repository-생성&#34;&gt;#&lt;/a&gt; 1) 새로운 Repository 생성&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;개별 Github의 프로필에서 우측의 이미지 선택후 Your Repositories  또는 좌측 상단에 있는 Repositories를 클릭해 개인 Repository 로 이동 후 New 를 눌러 새로운 Repository 를 생성합니다.&lt;br /&gt;
&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/TFc9ZQa.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이제 적절한 Repository 이름을 만들고 적당히 설명도 작성해줍니다. 저는 분류하기 애매한 잡다한 코드들을 모아두는 곳이란 의미로 &amp;quot;MiscellaneousRepos&amp;quot; 라고 이름지어봤습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;기존에 공부하기 위해 fork했던 repository 나, 굳이 메인에 보일 필요 없는 모든 repository 들을 이곳에 옮길 생각입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/mvcvqls.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;다음으로는 생성한 Repository를 내 Local로 Clone 합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;일단 간단하게 &lt;a href=&#34;http://README.md&#34;&gt;README.md&lt;/a&gt; 파일 하나 생성해준 뒤, Clone할 Repository 의 주소를 복사합니다.&lt;/p&gt;
&lt;p&gt;💡다음 단계의 로컬 git에서 첫번째로 할 작업이 commit 인데, 이를위해 미리 README.md를 하나 만들어 두는게 편합니다.&lt;br /&gt;
별도의 수정없이  &lt;code&gt;git add .&lt;/code&gt;  한 후에 commit을 해도 되지만, 종종 &#39;변동사항이 없어 commit이 불가능하다&#39;고 뜨는 경우가 있어서 미리 생성하는게 더 편리합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/19wUB1e.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h4 id=&#34;2-내-local에-생성한-repository-clone-및-commit하기&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-내-local에-생성한-repository-clone-및-commit하기&#34;&gt;#&lt;/a&gt; 2) 내 Local에 생성한 Repository Clone 및 Commit하기&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;저 같은 경우 github desktop을 사용하고 있어 바로 프로그램을 통해 폴더를 지정하고 clone을 했습니다.&lt;br /&gt;
(github desktop에 대한 사용법은 차후 기회가 되면 정리해서 포스팅 하겠습니다.)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;git 만 컴퓨터에 설치한 상태라면 다음의 단계를 따라 작업합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;Clone할 레포지토리를 저장할 폴더로 이동 또는 생성한다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;해당 폴더를 우클릭해 Open Git Bash here 를 클릭해 해당 폴더를 경로로 하는 git command 창을 엽니다.&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/XazNTEa.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;그럼 아래의 이미지와 같이 git command 창이 열리며 해당 경로로 접속된 걸 확인할 수 있습니다.&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/KQCbixv.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이제 아래의 코드를 각각 입력해 줍니다.&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/j66yyLI.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;git init으로 저장소를 생성해줍니다. (저의 경우 해당 폴더에 이미 다른 레포지토리를 클론 해둔 상태라  &lt;code&gt;Reinitialized existing Git repository in~&lt;/code&gt;  이란 메시지가 뜹니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이후  &lt;code&gt;git clone + 복사한 repository 주소.git&lt;/code&gt;  를 입력해 clone합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;정상적으로 clone이 되었다면 위의 이미지와 같은 메시지들이 출력 됩니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;이제 clone된 repository에 에 수정작업을 하고 commit을 해줍니다.&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;clone한 repository에 아무작업 없이 다른 repository를 합치는 작업을 하면 git은 변동사항이 없다고 판단합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이 경우  &lt;code&gt;Working tree has modification. Cannot add&lt;/code&gt;  라는 에러가 발생합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이를 방지하기 위해 적어도 1번 이상의 commit을 해야 합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;미리 생성해둔 README.md를 열어서 문구를 조금 수정해도 되고, 아무런 작업을 하지 않고도 아래의 코드를 입력해서 commit을 할 수 있습니다. (commit 불가하다고 나오면 README를 간단하게 수정하고 다시 시도해주세요🫡)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code&gt;$ git add .
$ git commit -m &amp;quot;message&amp;quot;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;repository-합치기2-생성한-repository-에-기존-repository-옮기기&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#repository-합치기2-생성한-repository-에-기존-repository-옮기기&#34;&gt;#&lt;/a&gt; Repository 합치기(2) - 생성한 Repository 에 기존 Repository 옮기기&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;아까  &lt;code&gt;git bash&lt;/code&gt; 로 열어둔 터미널에서 이어서 작업 합니다.&lt;/li&gt;
&lt;li&gt;해당 터미널에서 아래의 명령어를 입력합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;$ &lt;span class=&#34;token function&#34;&gt;git&lt;/span&gt; subtree &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;--prefix&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;옮길repo이름 옮길repo주소 옮길_repo의_branch명&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;현재 Repository에 합치고자 하는 모든 repository에 대해 위 코드를 사용해 1줄 씩 입력해주면 됩니다.&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;💡이때, 옮기려고 하는 repository 의 branch가 main 또는 master 경우에 따라서는 user가 지정한 별도의 이름일 수도 있으니 이를 잘 확인해야 합니다.&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;저 같은 경우 SQL용으로 연동 해 놓은 repository의 경우 branch이름이 2개의 branch가 있었고 이중 하나는 SQL이었습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;정상적으로 subtree가 생성되었다면 아래와 같은 메시지가 출력 되어야 합니다.&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/YMoHXg5.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;repository-합치기-3-subtree로-옮긴-repository에-push하기&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#repository-합치기-3-subtree로-옮긴-repository에-push하기&#34;&gt;#&lt;/a&gt; Repository 합치기 (3) - Subtree로 옮긴 Repository에 push하기&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;이제 Repository를 합치기 위한 최종 작업입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이 작업까지 완료를 해야 정상적으로 Repository 합치기 작업이 완료 됩니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;(1)~(2) 까지는 여러 Repository를 옮기기 위한 공간을 만들고, 그 공간안에 옮기는 작업을 했습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이제는 원격저장소(GitHub)에 push를 함으로써 git에서 subtree로 여러 repository를 옮긴 것들을 push해서 업데이트 해줘야 합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;git push origin HEAD:main --force&lt;/code&gt;  코드를 git command 창에 입력해주면 됩니다.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;아래와 같은 결과가 뜬다면 성공적으로 작업이 완료된 것입니다.&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/Zk5hl4u.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이후 실제 저의 &lt;a href=&#34;GitHub.md&#34;&gt;GitHub&lt;/a&gt; 으로 이동해서 subtree를 생성한 Repository에 가보면 아래와 같이 Repository들이 성공적으로 옮겨진 것을 알 수 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/T3arQo8.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;repository-합치기-4-옮긴-repository-원본-삭제하기&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#repository-합치기-4-옮긴-repository-원본-삭제하기&#34;&gt;#&lt;/a&gt; Repository 합치기 (4) - 옮긴 Repository 원본 삭제하기&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;이제 Subtree로 특정 Repository 에 옮기고난 원본 repository 를 삭제할 수 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이미 해당 repository 에 대한 모든 정보가 subtree로 옮겨졌기 때문에 기존 repository 를 삭제해도, 과거의 모든 commit을 유지할 수 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h2 id=&#34;어떻게-이런-작업이-가능한가-feat-subtree&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#어떻게-이런-작업이-가능한가-feat-subtree&#34;&gt;#&lt;/a&gt; 🤔 어떻게 이런 작업이 가능한가? (feat. subtree)&lt;/h2&gt;
&lt;p&gt;🔍 상세내용 살펴보기&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;이제 모든 작업이 잘 이뤄지고 원하는대로 구현이 되었으니, 원리를 살펴봅니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;위 작업에는 git의 subtree라는 개념이 사용되었습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이 subtree라는 것이 무엇인지, 어떻게 위와 같은 작업이 이뤄지는지, 왜 기존 commit이 유지되는 지를 정리합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✔️ subtree란?&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;subtre는 Git에서 사용하는 개념으로, 한 repository 안에서 다른 repository로 sub-directory 형태로 통합할 수 있게 해주는 기능입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;이는 여러 프로젝트나 라이브러리를 하나의 repository 에서 관리할 수 있게 하고, sub-directory 는 독립적인 repository 로써 본연의 특징을 그대로 유지하는 특성을 가지고 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✔️  원래 subtree는 어떨때 쓰는걸까?&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;분리된 프로젝트 관리&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;서로 다른 프로젝트를 하나의 repository 에서 관리할 수 있기 때문에 각 프로젝트 간 의존성 관리 및 코드 공유가 용이합니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;독립적인 개발 가능&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;각 sub-directory 는 독립적인 개발 흐름을 유지할 수 있으므로, 큰 프로젝트 내에서 작은 부분들을 개별적으로 관리할 수 있게 해줍니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;✔️ &lt;a href=&#34;https://git-memo.readthedocs.io/en/latest/subtree.html&#34;&gt;git 공식문서&lt;/a&gt; 의 내용을 보면 subtree에 대해 더 다양한 정보를 확인할 수 있습니다.&lt;/p&gt;
&lt;p&gt;✔️ subtree로 옮긴후 기존 repository 를 삭제해도 기록이 남는 이유?&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;subtree 를 할때 기존 repository 의 commit 내역들도 모두 함께 복사가 됩니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;따라서 원본 repository 를 삭제해도 통합된 repository 에 남아있는 commit 기록으로 인해 과거의 기록이 유지됩니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;또한 이렇게 생성된 subtree는 자체적으로 &#39;독립된 repository &#39; 이기 때문에 원본 repository 의 삭제나 commit등에 영향을 받지 않습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;✔️ 그렇다면 branch를 새로 만들어서 작업하는것과 subtree는 뭐가 다른가?!&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;개념적으로 branch를 새로만드는 것과 기존 repository 를 subtree로 작업하는 것은 다르며 그 목적도 다릅니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;Branch&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;branch는 동일한 repository 안에서 다른 개발 흐름을 만들기 위한게 목적입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;주로 기능개발, 버그 수정, 실험 등을 메인 라인과 분리하여 관리하고자 할때 사용합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;branch는 같은 코드 베이스를 공유하며, 다른 branch로 부터 분기하거나 다시 병합되는 것이 가능합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Subtree&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;subtree는 완전히 다른 repository 를 현재 repository 의 sub-repository로서 통합하는데 사용합니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;서로 다른 프로젝트, repository 를 하나의 repository 안에서 관리하는 것이 주 목적입니다.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;subtree를 사용하면, 통합된 repository는 원본 repository 의 commit 내역과 독립성을 유지합니다. (= 영향을 받지 않는다.)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;또한 기존 repository 와 subtree한 repository 는 별도의 개발 흐름을 가질 수 있습니다.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;즉, branch는 동일한 repository  내에서 다양한 개발 라인을 관리하는 데 사용되며, subtree는 서로 다른 repository 들을 하나의 repository  안에서 관리하는 데 사용됩니다.&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;Hackers Ground에서 진행한 GitHub로 나만의 프로필 및 이력서 만들기에 대한 영상을 보고 내용을 정리+Review 했습니다.&lt;/p&gt;
&lt;h2 id=&#34;summary&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#summary&#34;&gt;#&lt;/a&gt; 🚦Summary&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;해당 포스팅은 &lt;a href=&#34;https://www.youtube.com/@hackersground-kr&#34;&gt;Hackers Ground&lt;/a&gt; 라는 채널에서 소개한 GitHub 프로필로 이력서 만들기 라는 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=JOSFY8vPftMzYz0I&#34;&gt;영상&lt;/a&gt; 을 보고 내용을 정리한 것을 소개합니다.&lt;/li&gt;
&lt;li&gt;해당 영상에서는 이력서와 포트폴리오 작성 방법에 대해 설명하고 있으며, 손쉽게 GitHub 프로필을 생성하는 방법도 소개합니다.
&lt;ul&gt;
&lt;li&gt;이력서는 연락처 정보와 기술 스택등을 포함해 지원 회사에 맞춰 커스터마이징 되어야 한다.&lt;/li&gt;
&lt;li&gt;경력과 프로젝트에 대한 내용을 중점적으로 적는 것이 좋다.&lt;/li&gt;
&lt;li&gt;GitHub프로필은 기본 프로필 &amp;amp; 다른 프로필로 나눌 수 있으며, 자기 소개와 전문성을 나타내는 파트이다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://arturssmirnovs.github.io/github-profile-readme-generator/&#34;&gt;GitHub Profile Readme Generator&lt;/a&gt; 를 통해 손쉽게 나만의 GitHub 프로필을 작성할 수 있다.&lt;/li&gt;
&lt;li&gt;참고로 해당 스트리밍을 진행해주신 &lt;a href=&#34;https://github.com/justinyoo&#34;&gt;Justin Yoo님의 GitHub 프로필&lt;/a&gt;은 링크와 같습니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h3 id=&#34;이-포스팅은-개인적-경험을-정리하는것을-주목적으로-합니다&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#이-포스팅은-개인적-경험을-정리하는것을-주목적으로-합니다&#34;&gt;#&lt;/a&gt; ⛔ 이 포스팅은 개인적 경험을 정리하는것을 주목적으로 합니다.&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;해당 포스팅의 작성 목적은 제가 배운 내용을 기록하는것이 최우선 목표이며, 포스팅 내용 일부에 개인적 경험, 영상에 없는 타 문서/영상/포스팅의 지식이 포함될 수 있습니다.
&lt;ul&gt;
&lt;li&gt;원본 영상에 없는 내용은 다른 색상으로 작성&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;주요 파트별로 참고하고싶은 내용만을 요약하였으며 더욱 상세한 내용은 원본 영상을 시청해보시길 권장 드립니다.&lt;/li&gt;
&lt;/ul&gt;
&lt;hr /&gt;
&lt;h2 id=&#34;1-이력서와-포트폴리오의-차이와-작성방법-영상-구간-intro~1324&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-이력서와-포트폴리오의-차이와-작성방법-영상-구간-intro~1324&#34;&gt;#&lt;/a&gt; 1. 이력서와 포트폴리오의 차이와 작성방법 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&#34;&gt;(영상 구간 : Intro~13:24)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;이력서는 객관적인 숫자와 경력을 통해 자신의 적합성을 보여주는 문서이다.&lt;/li&gt;
&lt;li&gt;포트폴리오는 자랑하고 싶은 능력과 성취를 종합적으로 보여주는 문서이다.
&lt;ul&gt;
&lt;li&gt;포트폴리오는 자신의 경력뿐만 아니라 학력, 프로젝트, 수상경력, 봉사활동 등을 포함해 작성할 수 있다&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;2-이력서-작성-요령-영상-구간-1324~2301&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-이력서-작성-요령-영상-구간-1324~2301&#34;&gt;#&lt;/a&gt; 2. 이력서 작성 요령 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&amp;amp;t=804&#34;&gt;(영상 구간 : 13:24~23:01)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;이력서에는 연락처 정보가 포함되어야 한다.
&lt;ul&gt;
&lt;li&gt;이메일 주소와 핸드폰번호등은 항상 최신화 되어 있어야 한다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;이력서는 지원회사에 맞춰 매번 커스터마이징 되어야 한다.
&lt;ul&gt;
&lt;li&gt;지원 직무나 분야에 맞는 기술 스택이나 목표를 적어야 한다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;이력서는 자기소개와 프로필 사진이 포함될 수 있다.
&lt;ul&gt;
&lt;li&gt;프로필 사진은 전문적이고 프로페셔널한 이미지를 보여줄 수 있는 것이 좋다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;이력서는 항상 현행화 되어야 한다. 연락처 정보나 기술 스택 등이 변경되었을 경우 업데이트 해야 한다
&lt;blockquote&gt;
&lt;p&gt;💡이전 회사에서 사수분께 조언받은 내용이긴 하지만 매번 업데이트가 어렵다면 적어도 분기에 한번은 자신의 이력서를 검토하고 업데이트하는 시간을 가져야 한다. (혹은 프로젝트가 끝날때마다)&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;3-이력서-작성시-주의-사항-영상-구간-2301~3157&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3-이력서-작성시-주의-사항-영상-구간-2301~3157&#34;&gt;#&lt;/a&gt; 3. 이력서 작성시 주의 사항 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&amp;amp;t=1381&#34;&gt;(영상 구간 : 23:01~31:57)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;이력서 작성 시 경력과 프로젝트에 대한 내용을 중점적으로 작성하는 것이 좋다.
&lt;ul&gt;
&lt;li&gt;경력은 어디서 일했는지, 어떤일을 했는지, 근무 기간등을 구체적으로 적는다.&lt;/li&gt;
&lt;li&gt;프로젝트는 프로젝트 이름, 기간, 역할, 성과등을 적는다.
&lt;ul&gt;
&lt;li&gt;성과는 가급적 수치화 하여 보는이로 하여금 즉각적으로 인지할 수 있도록 한다. (과정에 대한 설명은 면접에서!)&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;학력은 경력이 많을 수록 중요하지 않으며, 학위와 졸업기간을 적는다.&lt;/li&gt;
&lt;li&gt;수상경력은 학력 부분이 아닌 별도로 적는 것이 좋다.&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;특정 회사에 지원시 해당 회사에 맞춰서 이력서를 정리해 보내는 것이 좋다.&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;4-github으로-프로필-작성하는-방법-영상-구간-3157~4201&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4-github으로-프로필-작성하는-방법-영상-구간-3157~4201&#34;&gt;#&lt;/a&gt; 4. GitHub으로 프로필 작성하는 방법 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&amp;amp;t=1917&#34;&gt;(영상 구간 : 31:57~42:01)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;GitHub 프로필은 기본 프로필과 기타 프로필로 나눌 수 있음
&lt;ul&gt;
&lt;li&gt;기본 프로필은 자기소개 부분
&lt;ul&gt;
&lt;li&gt;자신의 전문성과 업무 포커스를 나타낼 수 있음&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;기타 프로필은 자신의 소속사, 현재위치, 블로그, 소셜 미디어 등을 추가로 작성&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;GitHub에서는 repository의 &lt;a href=&#34;http://README.md&#34;&gt;README.md&lt;/a&gt; 파일을 이용해 이력서를 작성할 수 있다.&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;이력서는 개발자 특화된 내용을 담고 있으며, 화려한 디자인보다는 필요한 내용을 간결하게 보여주는 것이 중요하다.&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;5-github-프로필-생성기를-이용해-자신의-github프로필을-손쉽게-꾸밀-수-있다-영상-구간-4201~5056&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5-github-프로필-생성기를-이용해-자신의-github프로필을-손쉽게-꾸밀-수-있다-영상-구간-4201~5056&#34;&gt;#&lt;/a&gt; 5. GitHub 프로필 생성기를 이용해 자신의 GitHub프로필을 손쉽게 꾸밀 수 있다. &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&amp;amp;t=2521&#34;&gt;(영상 구간 : 42:01~50:56)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://arturssmirnovs.github.io/github-profile-readme-generator/&#34;&gt;GitHub Profile Readme Generator&lt;/a&gt;를 사용하면 자신만의 GitHub프로필을 만들 수 있다.&lt;/li&gt;
&lt;li&gt;프로필 생성기에서 기본적인 포맷을 설정하고, 필요한 정보를 입력하면 마크다운 문서가 생성&lt;/li&gt;
&lt;li&gt;생성된 마크다운 문서를 복사해 깃허브 프로필에 붙여넣으면 된다.&lt;/li&gt;
&lt;li&gt;생성된 마크다운 문서는 영어로 되어있다.(한글로 바꾸는건 스스로 작업필요)&lt;/li&gt;
&lt;li&gt;생성된 프로필의 기본정보에서 자신에 맞게 커스터마이징 할 수 있다.&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;6-github-프로필-작성하기-영상-구간-5056~010651&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6-github-프로필-작성하기-영상-구간-5056~010651&#34;&gt;#&lt;/a&gt; 6. GitHub 프로필 작성하기 &lt;a href=&#34;https://www.youtube.com/live/Pe28SY8Cn5A?si=Ny4CGvHDDp-yG3RO&amp;amp;t=3056&#34;&gt;(영상 구간 : 50:56~01:06:51)&lt;/a&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;GitHub 프로필에는 자신의 정보와 SNS계정을 추가할 수 있다.&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://arturssmirnovs.github.io/github-profile-readme-generator/&#34;&gt;GitHub Profile Readme Generator&lt;/a&gt;를 이용하면 템플릿에 맞게 정보를 입력하고 미리보기로 확인이 가능하다.&lt;/li&gt;
&lt;li&gt;프로필에는 자기소개, 학력, 기술, 활동 경력 등을 작성할 수 있다.&lt;/li&gt;
&lt;li&gt;마크다운으로 작성한 프로필을 복사해 GitHub의 본인 User명이 있는 &lt;a href=&#34;http://README.md&#34;&gt;README.md&lt;/a&gt; 에 붙여넣으면 메인화면에 이력서가 보여진다.&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;github-프로필-생성기-사용법&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#github-프로필-생성기-사용법&#34;&gt;#&lt;/a&gt; GitHub 프로필 생성기 사용법&lt;/h4&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; src=&#34;https://i.imgur.com/5KdAQtH.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;review&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#review&#34;&gt;#&lt;/a&gt; Review&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;마크다운은 현실적으로 개발자/AI를 다루는사람들이 가장 많이 다루는 문서작성 툴중 하나일 것이다.&lt;/li&gt;
&lt;li&gt;그런 면에서 마크다운을 활용해 문서를 다양하게 꾸미고 커스터마이징하는 방법은 확실히 배워둘 필요가 있다.&lt;/li&gt;
&lt;li&gt;GitHub는 실무에선 협업툴이지만 취업준비를 하는 입장에선 사실 개인 코드저장소와 같은 곳이 되는 곳이다.&lt;/li&gt;
&lt;li&gt;스스로 하는 포트폴리오, 공부한 내용등 다양한 코드를 저장해둘 수 있다.&lt;/li&gt;
&lt;li&gt;그렇기에 오히려 내 프로필과 이력서를 보여주는 공간으로서 적합한 것 같다.&lt;/li&gt;
&lt;li&gt;하지만 이력서, 프로필을 작성하는것에는 많은 고민이 든다. (이왕이면 잘 보여야 하고 fancy해야 하니까!)&lt;/li&gt;
&lt;li&gt;그런면에서 GitHub Profile Readme Generator는 상대적으로 기본적인 틀을 손쉽게 만들 수 있어서 좋은 것 같다.&lt;/li&gt;
&lt;li&gt;차후에 포폴이 좀 더 쌓이면 이를 사용해서 GitHub 이력서를 수정해볼 생각이다.&lt;/li&gt;
&lt;/ul&gt;
